import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.B8zgMDLd.js";const h=JSON.parse('{"title":"Open Or Create A Vault","description":"","frontmatter":{},"headers":[],"relativePath":"start/open-or-create-vault.md","filePath":"start/open-or-create-vault.md"}'),n={name:"start/open-or-create-vault.md"};function i(l,e,s,d,p,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="open-or-create-a-vault" tabindex="-1">Open Or Create A Vault <a class="header-anchor" href="#open-or-create-a-vault" aria-label="Permalink to &quot;Open Or Create A Vault&quot;">​</a></h1><p>A Tolaria vault is a folder on disk. The folder can contain Markdown notes, attachments, type definitions, saved views, and Git metadata.</p><h2 id="open-an-existing-folder" tabindex="-1">Open An Existing Folder <a class="header-anchor" href="#open-an-existing-folder" aria-label="Permalink to &quot;Open An Existing Folder&quot;">​</a></h2><p>Choose an existing folder if you already have Markdown notes. Tolaria scans <code>.md</code> files and uses frontmatter when it exists.</p><p>Good starting points:</p><ul><li>A folder of plain Markdown files.</li><li>An Obsidian-style vault.</li><li>A Git repository containing notes.</li><li>A copy of the Getting Started vault.</li></ul><h2 id="create-a-new-vault" tabindex="-1">Create A New Vault <a class="header-anchor" href="#create-a-new-vault" aria-label="Permalink to &quot;Create A New Vault&quot;">​</a></h2><p>Choose a new empty folder if you want Tolaria conventions from the start. New notes and optional type definitions are created as Markdown files.</p><h2 id="git-is-recommended-not-required" tabindex="-1">Git Is Recommended, Not Required <a class="header-anchor" href="#git-is-recommended-not-required" aria-label="Permalink to &quot;Git Is Recommended, Not Required&quot;">​</a></h2><p>Tolaria works well with a plain folder of Markdown files. You can open, edit, organize, and search notes without making the vault a Git repository.</p><p>Git is recommended when you want local history, diff views, recovery, pull, push, and remote sync without a proprietary backend. If a vault is not already a repository, Tolaria can initialize one when you explicitly ask it to.</p>',11)])])}const f=a(n,[["render",i]]);export{h as __pageData,f as default};
